sql:
SELECT AVG(hours_per_week) AS average_hours_per_week
FROM adult_population
WHERE age BETWEEN 18 AND 65;

SELECT person_id
FROM adult_population
WHERE age > 50 AND employment_status = 'unemployed';

SELECT user_name, role, department
FROM users
WHERE role = 'researcher' OR department = 'sales';

SELECT COUNT(*), income
FROM adult_population
GROUP BY income;

external_knowledge:
- 'Single' refers to marital status 'Never-married';
- 'Middle-aged' generally refers to individuals aged between 35 and 50;
- 'Earnings' refer to the salary of the individuals;
- 'Local government positions' refer to workclass 'Local-gov'.

- 'young stars' refers to individuals in the adult population;
- 'outshine the average light of their professional constellation' implies having a salary higher than the average salary of their occupation;
- 'brightness of their youth' metaphorically refers to sorting by age;
- 'professional constellation' is a metaphor for the occupation.

sql:
SELECT a.person_id, a.age, a.salary
FROM adult_population a
WHERE a.salary = (SELECT MAX(salary) FROM adult_population);

external_knowledge:
More experienced, well-educated folks: Those with more than a high school education (numerical education level > 12); Working: Employment status is 'employed'; In the United States: Native country is 'United States'.;
Average age > 35: Total combined age of group divided by number of individuals > 35.;
Total earnings > 1,000,000: Sum of individual salaries in the group must exceed $1,000,000.

sql:
SELECT marital_status_name
FROM marital_statuses
WHERE average_age > 50;

SELECT DISTINCT user_name, department
FROM users
WHERE role = 'data analyst' AND access_level = 'write';
